class Solution {
public:
    int findTheLongestSubstring(string s) {
        int count[5] = {0, 0, 0, 0, 0}; // Initialize arrays for counting vowels
        int max_len = 0; // Initialize variable for storing maximum length

        for (int i = 0; i < s.length(); i++) {
            if (s[i] == 'a' || s[i] == 'e' || s[i] == 'i' || s[i] == 'o' || s[i] == 'u') {
                count[s[i] - 'a']++; // Increment count for the current vowel
                max_len = max(max_len, count[s[i] - 'a']); // Update max_len if count is greater
            }
        }

        return max_len;
    }
};
```

